(window.webpackJsonp=window.webpackJsonp||[]).push([[212],{839:function(r,n){r.exports="\x3c!-- \r\ntitle: 07-PythonIO\r\nsort: \r\n--\x3e \r\n# PythonIO编程\r\n\r\n> 涉及到数据交换的地方，IO操作会有Input和Output两个数据流。\r\n>\r\n> 同步和异步的区别就在于是否等待IO执行的结果。\r\n\r\n## 文件读写\r\n\r\n- 读取文件\r\n\r\n  ```python\r\n  f = open('/Users/michael/test.txt', 'r')\t# 打开一个文件\r\n  f.read()\t\t\t# 把文件读取到内存\r\n  f.readline()\t\t# 防止文件过大\r\n  f.close()\t\t\t# 关闭文件对象\r\n  ```\r\n\r\n  > 由于文件读写时都有可能产生`IOError`，一旦出错，后面的`f.close()`就不会调用。所以，为了保证无论是否出错都能正确地关闭文件，我们可以使用`try ... finally`来实现：\r\n  >\r\n  > 可以使用更简洁的`with`语句调用方法。\r\n  >\r\n  > ```python\r\n  > with open('/path/to/file', 'r') as f:\r\n  >     print(f.read())\r\n  > ```\r\n\r\n- **file-like Object**\r\n\r\n  > 像`open()`函数返回的这种有个`read()`方法的对象，在Python中统称为file-like Object。除了file外，还可以是内存的字节流，网络流，自定义流等等。file-like Object不要求从特定类继承，只要写个`read()`方法就行。\r\n\r\n- 传入参数\r\n\r\n  ```python\r\n  f = open('test.txt', 'rb')\t\t\t\t\t\t# 二进制文件\r\n  f = open('gbk.txt', 'r', encoding='gbk')\t\t# 设置编码\r\n  f = open('gbk.txt', 'r', errors='ignore')\t\t# 忽略错误\r\n  ```\r\n\r\n- 写文件\r\n\r\n  ```python\r\n  f = open('test.txt','w')\t\t# 覆盖写入\r\n  f.write('Hello TXT.')\r\n  f.close()\r\n  \r\n  with open('test.txt','a') as f:\t# 追加写入\r\n  \tf.write('hhh')\r\n  ```\r\n\r\n## CSV\r\n\r\n```python\r\nimport csv\r\n# 读取\r\ncsv.read(open(file_name,'r'))\t# 返回一个二维列表\r\n\r\n# 写入\r\nf = open(file_name, 'r', newline='')\r\nw_csv = csv.writer(f)\t# 列表\t\r\nw_csv.writerow(list)\r\nw_csv.writerows(list(list))\r\n\r\nw_csv = csv.DictWriter(f,headers)\t# 字典，需要传入字段名称\r\nf_csv.writeheader()\r\nf_csv.writerows(rows)\r\n\r\n\r\n```\r\n\r\n## StringIO\r\n\r\n- 在内存中读写str\r\n\r\n  ```python\r\n  from io import StringIO\r\n  \r\n  f = StringIO()\r\n  f.write('Hello')\r\n  f.write(' ')\r\n  f.write('fzf')\r\n  print(f.getvalue())\t\t\t\t# 获取str\r\n  ```\r\n\r\n- **ByteIO**\r\n\r\n  ```python\r\n  from io import BytesIO\r\n  \r\n  f = BytesIO()\r\n  f.write('中文'.encode('utf-8'))\r\n  # f.write(r'\\xe4...')\r\n  print(f.getvalue())\t\t\t# b'\\xe4\\xb8……\r\n  ```\r\n\r\n## 操作文件和目录\r\n\r\n- os模块\r\n\r\n  ```python\r\n  import os\r\n  os.name()\t\t\t\t# 系统类型\r\n  os.uname()\t\t\t\t# 系统详细信息（windows不提供）\r\n  os.environ\t\t\t\t# 系统环境变量\r\n  os.environ.get('PATH')\t# 获取特定环境变量的值\r\n  # 文件和目录\r\n  os.path.abspath('')\t\t# 文件绝对目录\r\n  path = os.path.join('path', new_folder)\t# 准备工作\r\n  # 该函数会自动返回系统对应的目录结构\r\n  os.mkdir(path)\t\t\t# 新建文件夹\r\n  os.path.spilt(path)\t\t# 将路径拆分\r\n  os.path.spiltext(path)\t# 直接得到文件扩展名\r\n  # 并不要求文件真实存在\r\n  os.rename(old, new)\t\t# 重命名\r\n  os.remove(file)\t\t\t# 删除\r\n  # 复制文件可以参考shutil函数\r\n  [x for x in os.listdir('.') if os.path.isdir(x)]\r\n  # 列出所有文件夹\r\n  # listdir(.)\t当前目录的所有文件及文件夹 \r\n  # isdir()\t\t判断是否为路径\r\n  [x for x in os.listdir('.') if os.path.isfile(x) and os.path.splitext(x)[1]=='.py']\r\n  # 列出所有py文件\r\n  ```\r\n\r\n\r\n## 序列化\r\n\r\n- 在程序运行过程中修改变量并不会保存。\r\n\r\n- 把变量从内存中变成磁盘中的过程叫序列化。\r\n\r\n  ```python\r\n  import pickle\r\n  \r\n  with open('dump.txt', 'wb') as f:\r\n      list = '1 2 3 4'.split()\r\n      pickle.dump(list, f)\r\n  with open('dump.txt', 'rb') as f:\r\n      list = pickle.load(f)\r\n      print(list)\r\n  ```\r\n\r\n### JSON\r\n\r\n- 在不同编程语言之间传递对象。\r\n\r\n- | JSON类型   | Python类型 |\r\n  | :--------- | :--------- |\r\n  | {}         | dict       |\r\n  | []         | list       |\r\n  | \"string\"   | str        |\r\n  | 1234.56    | int或float |\r\n  | true/false | True/False |\r\n  | null       | None       |\r\n\r\n  ```python\r\n  import json\r\n  dj = json.dumps(d)\t\t\t\t# 返回一个json格式的str\r\n  d = json.load(dj)\t\t\t\t# 转换回来\r\n  ```\r\n\r\n- 将`class`转换为JSON。\r\n\r\n  ```python\r\n  import json\r\n  \r\n  class Student(object):\r\n      def __init__(self, name, age, score):\r\n          self.name = name\r\n          self.age = age\r\n          self.score = score\r\n          \r\n  def student2dict(std):\t\t\t\t# 写一个转换函数\r\n      return {\r\n          'name': std.name,\r\n          'age': std.age,\r\n          'score': std.score\r\n      }\r\n      \r\n  s = Student('Bob', 20, 88)\r\n  print(json.dumps(s, default = student2dict))\r\n  ```\r\n\r\n  "}}]);